# exercises layer-wide COMPOSITE { OPACITY n, COMPOP "..." } -> Style.opacity
# and Style.blend_mode lowering. OPACITY 50 becomes 0.5; COMPOP multiply maps
# to BlendMode::Multiply; both apply to every class style emitted under the
# layer.
MAP
  NAME "composite_test"
  TITLE "Composite Opacity"

  LAYER
    NAME "roads"
    TYPE LINE
    STATUS ON
    DATA "geom FROM roads_table"

    COMPOSITE
      OPACITY 50
      COMPOP "multiply"
    END

    CLASS
      NAME "default"
      STYLE
        COLOR 200 50 50
        WIDTH 1.0
      END
    END
  END
END
